   178	    private static bool TryReadEnvFile(string filePath,
   179	                                       Dictionary<string, string> environment)
   180	    {
   181	        Debug.Assert(!string.IsNullOrEmpty(filePath), "The file path must be specified.");
   182	        Debug.Assert(environment != null, "The environment dictionary must be specified.");
   183	
   184	        if (!File.Exists(filePath))
   185	        {
   186	            return false;
   187	        }
   188	
   189	        var count = 0;
   190	
   191	        foreach (var fileLine in File.ReadLines(filePath))
   192	        {
   193	            ++count;
   194	
   195	            var line = fileLine.AsSpan();
   196	            var firstCharacterPos = FindFirstCharacterIndex(line);
   197	
   198	            if ((firstCharacterPos == -1) || (line[firstCharacterPos] == '#'))
   199	            {
   200	                continue;
   201	            }
   202	
   203	            var separator = line.IndexOf('=');
   204	
   205	            if ((separator == -1) || (separator <= firstCharacterPos))
   206	            {
   207	                throw new FormatException($"The environment file is malformed at line {count}");
   208	            }
   209	
   210	            var length = separator - firstCharacterPos;
   211	            var parsedKey = line.Slice(firstCharacterPos, length).Trim().ToString();
   212	            var parsedValue = line.Slice(separator + 1).Trim().Trim('"').ToString();
   213	
   214	            // Set the value unconditionally, clobbering any existing data.
   215	            environment[parsedKey] = parsedValue;
   216	        }
   217	
   218	        return true;
   219	    }
   220	
   221	    [MethodImpl(MethodImplOptions.AggressiveInlining)]
   222	    private static int FindFirstCharacterIndex(ReadOnlySpan<char> line)
   223	    {
   224	        var position = 0;
   225	        var length = line.Length;
   226	
   227	        while ((position < length) && (char.IsWhiteSpace(line[position])))
   228	        {
   229	            ++position;
   230	        }
   231	
   232	        return (position < length) ? position : -1;
   233	    }
